export type ProjectKind =
  | "company" | "book" | "software" | "research" | "website" | "other";

export type ProjectStatus =
  | "active" | "draft" | "shipping" | "shipped" | "archived";

export type ProjectMetadataStatus = "exploration" | "in-progress" | "shipped";

export type ProjectExternalLink = {
  label: string;
  href: string;
};

export type ProjectMetadata = {
  slug: string;
  code: string;
  title: string;
  tagline: string;
  status: ProjectMetadataStatus;
  framing: string;
  externalLinks?: ProjectExternalLink[];
  seedQuestion?: string;
};

export type ProjectVisibility = "default" | "teaser";

export type ProjectLink = {
  label: string;
  href: string;
  external?: boolean;
};

export type Project = {
  slug: string;
  code: string;
  title: string;
  tagline: string;
  kind: ProjectKind;
  status: ProjectStatus;
  startedISO: string;
  updatedISO: string;
  stage?: string;
  links: ProjectLink[];
  summary: string;
  customPage?: string;
  mediaHeroSrc?: string;
  classification?: "public" | "restricted" | "private";
  visibility?: ProjectVisibility;
  citation?: string;
  authors?: string[];
};

import type { ProjectMetadata } from "@/lib/projects/types";

// Tagline sourced from src/content/projects/hivemind/thesis.ts.
// Framing composed from thesis.ts (mechanism), capabilities.ts (CAP list),
// workflow.ts (six-step pipeline), and the layered scoring contract in
// src/lib/coherenceEngine/arguments.ts (CE2 §2-§4).
export const metadata: ProjectMetadata = {
  slug: "hivemind",
  code: "HVM",
  title: "Hivemind",
  tagline: "Strategic analytical software.",
  status: "in-progress",
  framing:
    "Hivemind decomposes strategy questions into evaluable hypotheses, attaches weighted evidence, and aggregates probabilistic posteriors into a structured brief. The output is a structured memo with citations and confidence intervals, not a chat transcript. The bet is that decision-grade analysis benefits from explicit structure scored against a layered coherence contract.",
  externalLinks: [
    { label: "hivemind.ai", href: "https://hivemind.ai" },
    { label: "app.hivemind.ai", href: "https://app.hivemind.ai" },
  ],
  seedQuestion: "what does Hivemind actually do?",
};

export default metadata;

