import { vi } from "vitest";
import React from "react";

vi.mock("next/link", () => ({
  default: ({
    href,
    children,
    ...rest
  }: React.AnchorHTMLAttributes<HTMLAnchorElement> & { href: string }) =>
    React.createElement("a", { href, ...rest }, children),
}));

import type { ProjectMetadata } from "@/lib/projects/types";

// Tagline + framing sourced from existing repo content:
//   - thesis.ts      → claim ("philosophical debate can be systematized"),
//                       method (extract first principles, graph supports/
//                       tensions, surface contradictions), role
//                       ("a Kim/Codex for the operator-philosopher")
//   - methodology.ts → extraction with provenance, Noosphere walking the
//                       graph, slow structured collaborator (not a chatbot)
//   - principles.ts  → the seed dataset (P-001..P-080) with explicit
//                       supports / tensions edges
// The intended src/lib/theseus/* files (ordersDeck.ts, thesisAxes.ts,
// sources.ts) referenced by the prompt do not currently exist in the repo;
// the framing therefore stays grounded in the content/ files above.
export const metadata: ProjectMetadata = {
  slug: "theseus",
  code: "THS",
  title: "Theseus",
  tagline:
    "A knowledge system for monitoring contradiction in the principles you have already committed to.",
  status: "shipped",
  framing:
    "Theseus extracts first principles from discussion and writing, links them into a graph of supports and tensions, and runs a second model — Noosphere — across the graph to flag contradictions, ask refining questions, and propose edits. The product is a slow, structured collaborator for the operator-philosopher who wants to know, at any given moment, where their stated commitments contradict themselves. The output is a contradiction map with provenance, not a debate.",
  externalLinks: [
    { label: "thesescodex.com", href: "https://thesescodex.com" },
  ],
  seedQuestion: "what does the Theseus project argue about identity?",
};

export default metadata;

import type { ProjectMetadata } from "@/lib/projects/types";

// Tagline + framing sourced from existing repo content:
//   - preface.ts / preface.mdx → severance of efficiency from purpose,
//     metric-as-meaning, "you have already noticed the symptoms"
//   - pillars.ts (I–V)        → corporatism, gamification, incumbency,
//                                complacency, economic revolution
//   - arc.ts                  → Book I of a five-volume series
//   - quotes.ts               → "Efficiency, severed from purpose, becomes
//                                the most efficient way of arriving nowhere."
export const metadata: ProjectMetadata = {
  slug: "purposeless-efficiency",
  code: "PRP",
  title: "Purposeless Efficiency",
  tagline: "Book I — efficiency severed from purpose.",
  status: "in-progress",
  framing:
    "Purposeless Efficiency is a book-length argument that the late industrial era has been reorganized around optimization without an examined end — efficiency severed from purpose, the metric become the meaning. Book I of a five-volume series, it traces the consequences across five pillars: corporatism, gamification, incumbency, complacency, and the shape of an economic revolution that does not repeat the failure modes of the last one.",
  externalLinks: [],
  seedQuestion: "what is purposeless efficiency?",
};

export default metadata;

